mapper.select:
SELECT COUNT(a.id) number, a.type_id dictDataId FROM crm_customer a
AND a.tenant_id = #{tenantId}
GROUP BY a.type_id

SELECT COUNT(a.id) number, a.from_id dictDataId FROM crm_customer a
AND a.tenant_id = #{tenantId}
GROUP BY a.from_id

SELECT COUNT(a.id) number, a.industry_id dictDataId FROM crm_customer a
AND a.tenant_id = #{tenantId}
GROUP BY a.industry_id

SELECT COUNT(a.id) number, a.group_id dictDataId FROM crm_customer a
AND a.tenant_id = #{tenantId}
GROUP BY a.group_id

SELECT COUNT(d.id) number, d.type_id dictDataId FROM crm_documentary d WHERE YEAR(d.create_time) = #{year}
AND d.tenant_id = #{tenantId}
GROUP BY d.type_id
